# C-unicode: allowlist bypass via Unicode normalization / homoglyph confusion.
import unicodedata

BLOCKLIST = {"admin"}  # security-sensitive reserved name

def naive_check(username):
    # VULNERABLE: compares raw bytes; downstream system NFKC-normalizes later
    return username.lower() not in BLOCKLIST

