    resolves_to = downstream_identity(attacker)
    if passed_gate and resolves_to == "admin":
        print(f"VULNERABLE: input {attacker!r} bypassed allowlist but resolves to {resolves_to!r}")
    else:
        print("PASS: normalization mismatch caught before the gate")

