# AUTHORIZED LAB ONLY -- signed RoE. Local in-process API stub only.
# C-replay: signed request with a nonce is accepted twice (no nonce store).
import hmac, hashlib

SECRET = b"FAKE-SHARED-SECRET"
BALANCE = {"acct": 100}
SEEN_NONCES = set()  # present but the vulnerable handler ignores it

def sign(nonce, amount):
    return hmac.new(SECRET, f"{nonce}:{amount}".encode(), hashlib.sha256).hexdigest()

def transfer(nonce, amount, sig, enforce_nonce=False):
    if not hmac.compare_digest(sig, sign(nonce, amount)):
        return "REJECT-BADSIG"
    if enforce_nonce:
        if nonce in SEEN_NONCES:
            return "REJECT-REPLAY"
        SEEN_NONCES.add(nonce)
    BALANCE["acct"] -= amount  # apply
    return "APPLIED"

def main():
    nonce, amount = "FAKE-NONCE-1", 30
    sig = sign(nonce, amount)
    # VULNERABLE path: nonce never recorded, so a captured request replays
    r1 = transfer(nonce, amount, sig, enforce_nonce=False)
    r2 = transfer(nonce, amount, sig, enforce_nonce=False)
    if r1 == "APPLIED" and r2 == "APPLIED" and BALANCE["acct"] == 40:
        print("VULNERABLE: replayed signed request applied twice (no nonce/replay cache)")
    else:
        print("PASS: replay rejected")

