# AUTHORIZED LAB ONLY -- signed RoE. Local concurrency-logic stub, no network.
# XC-ratelimit-workflow-bypass: a check-then-act gate is bypassed when requests interleave.
class Coupon:
    def __init__(self):
        self.remaining = 1   # single-use
        self.redeemed = 0

def main():
    c = Coupon()
    N = 5  # N concurrent requests arriving before any write commits

    # Deterministic interleaving: all N read state (gate open) BEFORE any decrement,
    # exactly what happens with non-atomic read-decide-write under concurrency.
    decisions = [c.remaining > 0 for _ in range(N)]   # all observe remaining=1
    for ok in decisions:                              # then each commits its write
        if ok:
            c.remaining -= 1
            c.redeemed += 1

    if c.redeemed > 1:
        print(f"VULNERABLE: single-use gate bypassed by interleaved requests; redeemed {c.redeemed} times "
              f"(fix: atomic compare-and-decrement / SELECT FOR UPDATE)")
