#!/usr/bin/env python3
# AUTHORIZED LAB ONLY -- signed RoE. Pure-logic crypto demo, no network.
# XC-weak-signature-collision: a truncated/weak digest accepts two distinct messages as equal.
import hashlib

# Vulnerable design: integrity "signature" = first 24 bits of SHA-256 (truncated digest).
def weak_tag(msg: bytes) -> str:
    return hashlib.sha256(msg).hexdigest()[:6]  # 24-bit tag -> collisions are trivially findable

def verify(msg: bytes, tag: str) -> bool:
    return weak_tag(msg) == tag

def main():
    benign = b"transfer:amount=10;to=alice@example.test"
    target_tag = weak_tag(benign)
    # Brute-force a DISTINCT malicious message with the same 24-bit tag (fast, ~2^24 worst case).
    forged = None
    for i in range(1 << 26):
        cand = b"transfer:amount=1000000;to=attacker@example.test;n=%d" % i
        if weak_tag(cand) == target_tag:
            forged = cand
            break
    if forged and forged != benign and verify(forged, target_tag):
        print(f"VULNERABLE: weak (24-bit) signature collides; forged message accepted under benign tag {target_tag}")
        print(f"  benign : {benign.decode()}")
        print(f"  forged : {forged.decode()}")
    else:
        print("PASS: no collision found within bound (use a full-width, collision-resistant MAC)")

