#!/usr/bin/env python3
# AUTHORIZED LAB ONLY -- signed RoE. Lab crypto on local synthetic data only, no network.
# XC-padding-oracle-nonce-reuse: (A) IV/nonce reuse in a stream cipher leaks plaintext XOR;
#                                (B) a CBC padding oracle recovers a plaintext byte.
import hashlib, os

# --- A toy block cipher (lab only; NOT for real use): keyed SHA-256 permutation of an 8-byte block.
BS = 8
def block_encrypt(key, block):
    return bytes(b ^ k for b, k in zip(block, hashlib.sha256(key + b"E").digest()[:BS]))
def block_decrypt(key, block):
    return bytes(b ^ k for b, k in zip(block, hashlib.sha256(key + b"E").digest()[:BS]))

def xor(a, b): return bytes(x ^ y for x, y in zip(a, b))

# --- Stream-cipher keystream derived from (key, nonce). Reusing nonce reuses keystream.
def keystream(key, nonce, n):
    out = b""; ctr = 0
    while len(out) < n:
        out += hashlib.sha256(key + nonce + ctr.to_bytes(4, "big")).digest()
        ctr += 1
    return out[:n]

def stream_encrypt(key, nonce, pt):
    return xor(pt, keystream(key, nonce, len(pt)))

def part_a_nonce_reuse():
    key = os.urandom(16)
    nonce = b"FAKE-NONCE"  # VULNERABLE: same nonce used for two messages
    p1 = b"SECRET: balance=4242"
    p2 = b"PUBLIC: hello world!"  # attacker-known plaintext, same length
    c1 = stream_encrypt(key, nonce, p1)
    c2 = stream_encrypt(key, nonce, p2)
    # Attacker knows p2; recovers p1 with no key: p1 = c1 ^ c2 ^ p2
    recovered = xor(xor(c1, c2), p2)
    return recovered == p1, recovered

# --- CBC padding oracle: oracle leaks whether PKCS#7 padding is valid on decrypt.
def pkcs7_pad(b):
    p = BS - (len(b) % BS); return b + bytes([p]) * p
def pkcs7_unpad(b):
    p = b[-1]
    if p < 1 or p > BS or b[-p:] != bytes([p]) * p:
        raise ValueError("bad padding")
    return b[:-p]

def cbc_encrypt(key, iv, pt):
    pt = pkcs7_pad(pt); prev = iv; out = b""
    for i in range(0, len(pt), BS):
        out += (prev := block_encrypt(key, xor(pt[i:i+BS], prev)))
